(function ($) {
    $("#reset").click(function (event) {
        event.preventDefault();
        $("#content1").val("");

    });


    $("#run").click(function (event) {
        event.preventDefault();
        $("#pre-loader").show();
        var form = new FormData();
        form.append('content',$("#content1").val());
        var check_value = 0;
        if ($("#check").is(':checked')) {
            check_value = 1;
        }

        form.append('check',check_value);
        var csrftoken_input = $("meta[name='csrf-token']");
        var csrftoken = csrftoken_input.attr("content");
        form.append('csrf_token',csrftoken);
        // console.log(csrftoken);
        $.ajaxSetup({
            'beforeSend':function(xhr,settings) {
                if (!/^(GET|HEAD|OPTIONS|TRACE)$/i.test(settings.type)) {
                    var csrftoken = $('meta[name=csrf-token]').attr('content');
                    xhr.setRequestHeader("X-CSRFToken", csrftoken)
                }
            }
        });
        $.ajax({
            url:'/api/predict',
            type:'POST',
            processData: false,
            contentType: false,
            data:form,
            success:function (data) {

                if (data['code'] == 200) {
                    var path = "http://127.0.0.1:5000/detail/" + data['data']
                    $('#alert_message').empty();
                    console.log(path);
                    var alert = '<div class="col-12 alert alert-success alert-dismissible" role="alert"><strong>成功！</strong> ' +
                        '具体的详细结果：<a style="color: blue" href=' + path + '>' + path + '</a> ' +
                        '<button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="关闭"></button>' +
                        '</div>';
                    $('#alert_message').append(alert);
                    $("#pre-loader").hide();
                }

                if (data['code'] == 400) {

                    $('#alert_message').empty();
                    var alert = '<div class="col-12 alert alert-danger alert-dismissible fade show" role="alert"><strong>error! </strong>'+ data['msg']  +'<button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button></div>'
                    $('#alert_message').append(alert);
                    $("#pre-loader").hide();
                }

            },
            fail:function (error) {

                $('#alert_message').empty();
                var alert = '<div class="col-12 alert alert-danger alert-dismissible fade show" role="alert"><strong>error! </strong>'+ error  +'<button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button></div>'
                $('#alert_message').append(alert);
                $("#pre-loader").hide();
                console.log(error);
            }

        });

    });

    // content1


})(jQuery);


function example1() {
    $("#content1").val(">lcl|Csinensis_orange1.1g033508m\n" +
        "\n");
}

